              type: "worked-example",
              id: "ex-alt-corr-1",
              title: "Full Altitude Correction — Sun Lower Limb",
              given: "Sextant altitude: 42° 18.6'\nIndex Error: 1.8' OFF the arc\nHeight of eye: 12 m\nMain correction (from almanac, Sun LL, ha ≈ 42°): +15.1'",
              find: "True Observed Altitude (Ho)",
