                { label: "Apply Dip (12m → Dip = −6.1', from tables)", text: "ha = 42° 20.4' − 6.1' = 42° 14.3'" },
                { label: "Apply Main Correction (+15.1' for Sun LL)", text: "Ho = 42° 14.3' + 15.1' = 42° 29.4'" }
