                { label: "Safe for tank entry", formula: "O2 > 21%  AND  HC < 1% LEL  AND  H2S < 1 ppm", note: "All three must be verified before personnel entry" },
                { label: "SOLAS IGS requirement", formula: "Crude tankers >= 20,000 DWT  |  Product tankers >= 40,000 DWT", note: "If IGS fails during cargo ops: stop all operations immediately" }
